use std::io;

fn main() {
  let mut input = String::new();
  io::stdin().read_line(&mut input).unwrap();

  let mut n: i32 = input.trim().parse().unwrap();

  let mut compare = n;
  let mut sum: i32 = 0;

  loop {
    while n > 0{
      sum += n % 10;
      n /= 10;
    }
    if sum % 4 == 0 {
      println!("{}", compare);
      break;
    } else {
      sum = 0;
      compare += 1;
      n = compare;

    }
  }
}
